const results = $input.first().json.results || [];
return results.map(p => ({ json: {
  pageId: p.id,
  caseName: p.properties?.['案名']?.title?.[0]?.plain_text || '(未命名)',
  caseId:   p.properties?.['案件編號']?.rich_text?.[0]?.plain_text || '',
  sourceUrl: p.properties?.['來源連結']?.url || '',
  fbPostUrl: p.properties?.['粉專貼文連結']?.url || '',
  currentStatus: p.properties?.['狀態']?.select?.name || ''
}})).filter(x => x.json.sourceUrl);

const responses = $input.all();
const sources = $('展開結果').all();
const keywords = ['已下架', '物件不存在', '已成交', '已售出', '查無此物件', '找不到該物件', '此物件已不存在', '很抱歉'];

return responses.map((resp, i) => {
  const inItem = sources[i]?.json || {};
  const r = resp.json || {};
  const status = Number(r.statusCode ?? r.status ?? 0);
  const body = String(r.body ?? r.data ?? '');
  const hitKeyword = keywords.find(k => body.includes(k)) || null;

  let isRemoved = false;
  let reason = '';
  // 只有『物件確定沒了』才下架：404/410，或頁面明講下架關鍵字。
  // 5xx / 403 / 逾時(status 0) 一律當還在架上 → 避免永慶站臨時掛掉時誤刪全部廣告。
  if (status === 404 || status === 410) { isRemoved = true; reason = `HTTP ${status}（網址失效）`; }
  else if (status === 200 && hitKeyword) { isRemoved = true; reason = `頁面含「${hitKeyword}」`; }
  else if (status >= 500 || status === 403 || status === 429 || status === 0) { isRemoved = false; reason = `暫時無法確認(HTTP ${status})，本次略過`; }

  return { json: {
    ...inItem,
    statusCode: status,
    isRemoved,
    reason,
    detectedAt: new Date().toISOString()
  }};
});

const j = $json;
const url = j.fbPostUrl || '';
// 粉專永久連結格式：https://www.facebook.com/{pageid}_{postid}
const m = url.match(/facebook\.com\/(\d+_\d+)/);
const fbPostId = m ? m[1] : '';
return [{ json: { ...j, fbPostId, hasFbPost: !!fbPostId } }];

const prep = $('備妥刪文').item.json;
const resp = $json || {};
const rb = resp.body ?? resp;
let ok, failed, errMsg = '';
if (!prep.hasFbPost) {
  // 沒有粉專貼文可刪（例如只建檔沒發過）→ 直接可標下架
  ok = true; failed = false;
} else {
  const success = rb === true || rb?.success === true || (typeof rb === 'string' && rb.includes('success'));
  errMsg = rb?.error?.message || '';
  // 貼文本來就不存在（已被手動刪過）也算成功
  const alreadyGone = /does not exist|Unsupported (get|delete) request|cannot be loaded|Object with ID/i.test(errMsg);
  ok = success || alreadyGone;
  failed = !ok;
}
return [{ json: { ...prep,
  fbDeleted: prep.hasFbPost && ok,
  fbDeleteFailed: failed,
  fbDeleteError: failed ? (errMsg || 'unknown') : '',
  markRemoved: ok
} }];

