const checked = $('判斷是否下架').all().map(i => i.json);
const total = checked.length;
const removedRaw = checked.filter(x => x.isRemoved);
const alive = total - removedRaw.length;
const today = new Date().toLocaleDateString('zh-TW', { timeZone: 'Asia/Taipei' });

let outcomes = [];
try { outcomes = $('判定刪除結果').all().map(i => i.json); } catch (e) { outcomes = []; }
const byPage = {};
outcomes.forEach(o => { byPage[o.pageId] = o; });

let text;
if (total === 0) {
  text = `🌅 下架偵測 ${today}\n\n沒有需要偵測的物件（全部都已撤除確認或已下架）。`;
} else if (removedRaw.length === 0) {
  text = `🌅 下架偵測 ${today}\n\n✅ 檢查 ${total} 筆，全部仍在架上。`;
} else {
  const lines = removedRaw.map(r => {
    const o = byPage[r.pageId] || {};
    let tag;
    if (o.fbDeleteFailed) tag = `⚠️粉專刪除失敗（${o.fbDeleteError}）→ 狀態未改，請手動刪貼文`;
    else if (o.fbDeleted) tag = '粉專貼文已自動刪除';
    else tag = '無粉專貼文';
    return `・${r.caseName}（${r.caseId}）— ${r.reason}；${tag}`;
  }).join('\n');
  const failCount = removedRaw.filter(r => (byPage[r.pageId] || {}).fbDeleteFailed).length;
  text = `🚨 下架偵測 ${today}\n\n檢查 ${total} 筆，發現 ${removedRaw.length} 筆已下架：\n\n${lines}\n\n${alive} 筆仍在架上。` + (failCount ? `\n\n⚠️ 其中 ${failCount} 筆粉專刪除失敗，需要你手動處理。` : '');
}

function safeGet(name) { try { return $(name).first()?.json; } catch (e) { return null; } }
const meta = safeGet('正規化（手動）') ?? safeGet('正規化（cron）') ?? { source: 'cron', replyToken: null };

return [{ json: {
  userId: 'Ufab42c56b2eb9b9a9ff18c367b85a6dd',
  summaryText: text,
  total,
  removedCount: removedRaw.length,
  source: meta.source,
  replyToken: meta.replyToken
} }];
